29: // scanState holds the state of an in-progress scan, to be passed to the various phases
30: type scanState struct {
31: 	progress          chan<- *ProgressInfo
32: 	fullScan          bool
33: 	changesDetected   atomic.Bool
34: 	libraries         model.Libraries  // Store libraries list for consistency across phases
35: 	targets           map[int][]string // Optional: map[libraryID][]folderPaths for selective scans
36: 	totalLibraryCount int              // Total number of libraries (unfiltered), for cross-library move detection
37: }
38: 
39: func (s *scanState) sendProgress(info *ProgressInfo) {
40: 	if s.progress != nil {
41: 		s.progress <- info
42: 	}
43: }
44: 
45: func (s *scanState) isSelectiveScan() bool {
46: 	return len(s.targets) > 0
47: }
48: 
49: func (s *scanState) sendWarning(msg string) {
50: 	s.sendProgress(&ProgressInfo{Warning: msg})
51: }
52: 
53: func (s *scanState) sendError(err error) {
54: 	s.sendProgress(&ProgressInfo{Error: err.Error()})
55: }
