57: func (s *scannerImpl) scanFolders(ctx context.Context, fullScan bool, targets []model.ScanTarget, progress chan<- *ProgressInfo) {
58: 	startTime := time.Now()
59: 
60: 	state := scanState{
61: 		progress:        progress,
62: 		fullScan:        fullScan,
63: 		changesDetected: atomic.Bool{},
64: 	}
65: 
66: 	// Set changesDetected to true for full scans to ensure all maintenance operations run
67: 	if fullScan {
68: 		state.changesDetected.Store(true)
69: 	}
70: 
71: 	// Get libraries and optionally filter by targets
72: 	allLibs, err := s.ds.Library(ctx).GetAll()
73: 	if err != nil {
74: 		state.sendWarning(fmt.Sprintf("getting libraries: %s", err))
75: 		return
76: 	}
77: 	state.totalLibraryCount = len(allLibs)
78: 
79: 	if len(targets) > 0 {
80: 		// Selective scan: filter libraries and build targets map
81: 		state.targets = make(map[int][]string)
82: 
83: 		for _, target := range targets {
84: 			folderPath := target.FolderPath
85: 			if folderPath == "" {
86: 				folderPath = "."
87: 			}
88: 			state.targets[target.LibraryID] = append(state.targets[target.LibraryID], folderPath)
89: 		}
90: 
91: 		// Filter libraries to only those in targets
92: 		state.libraries = slice.Filter(allLibs, func(lib model.Library) bool {
93: 			return len(state.targets[lib.ID]) > 0
94: 		})
95: 
96: 		log.Info(ctx, "Scanner: Starting selective scan", "fullScan", state.fullScan, "numLibraries", len(state.libraries), "numTargets", len(targets))
97: 	} else {
98: 		// Full library scan
99: 		state.libraries = allLibs
100: 		log.Info(ctx, "Scanner: Starting scan", "fullScan", state.fullScan, "numLibraries", len(state.libraries))
101: 	}
102: 
103: 	// Store scan type and start time
104: 	scanType := "quick"
105: 	if state.fullScan {
106: 		scanType = "full"
107: 	}
108: 	if state.isSelectiveScan() {
109: 		scanType += "-selective"
110: 	}
111: 	_ = s.ds.Property(ctx).Put(consts.LastScanTypeKey, scanType)
112: 	_ = s.ds.Property(ctx).Put(consts.LastScanStartTimeKey, startTime.Format(time.RFC3339))
113: 
114: 	// if there was a full scan in progress, force a full scan
115: 	if !state.fullScan {
116: 		for _, lib := range state.libraries {
117: 			if lib.FullScanInProgress {
118: 				log.Info(ctx, "Scanner: Interrupted full scan detected", "lib", lib.Name)
119: 				state.fullScan = true
120: 				if state.isSelectiveScan() {
121: 					_ = s.ds.Property(ctx).Put(consts.LastScanTypeKey, "full-selective")
122: 				} else {
123: 					_ = s.ds.Property(ctx).Put(consts.LastScanTypeKey, "full")
124: 				}
125: 				break
126: 			}
127: 		}
128: 	}
129: 
130: 	// Prepare libraries for scanning (initialize LastScanStartedAt if needed)
131: 	err = s.prepareLibrariesForScan(ctx, &state)
132: 	if err != nil {
133: 		log.Error(ctx, "Scanner: Error preparing libraries for scan", err)
134: 		state.sendError(err)
135: 		return
136: 	}
137: 
138: 	err = run.Sequentially(
139: 		// Phase 1: Scan all libraries and import new/updated files
140: 		runPhase[*folderEntry](ctx, 1, createPhaseFolders(ctx, &state, s.ds, s.cw)),
141: 
142: 		// Phase 2: Process missing files, checking for moves
143: 		runPhase[*missingTracks](ctx, 2, createPhaseMissingTracks(ctx, &state, s.ds)),
144: 
145: 		// Phases 3 and 4 can be run in parallel
146: 		run.Parallel(
147: 			// Phase 3: Refresh all new/changed albums and update artists
148: 			runPhase[*model.Album](ctx, 3, createPhaseRefreshAlbums(ctx, &state, s.ds)),
149: 
150: 			// Phase 4: Import/update playlists
151: 			runPhase[*model.Folder](ctx, 4, createPhasePlaylists(ctx, &state, s.ds, s.pls, s.cw)),
152: 		),
153: 
154: 		// Final Steps (cannot be parallelized):
155: 
156: 		// Run GC if there were any changes (Remove dangling tracks, empty albums and artists, and orphan annotations)
157: 		s.runGC(ctx, &state),
158: 
159: 		// Refresh artist and tags stats
160: 		s.runRefreshStats(ctx, &state),
161: 
162: 		// Update last_scan_completed_at for all libraries
163: 		s.runUpdateLibraries(ctx, &state),
164: 
165: 		// Optimize DB
166: 		s.runOptimize(ctx),
167: 	)
168: 	if err != nil {
169: 		log.Error(ctx, "Scanner: Finished with error", "duration", time.Since(startTime), err)
170: 		_ = s.ds.Property(ctx).Put(consts.LastScanErrorKey, err.Error())
171: 		state.sendError(err)
172: 		return
173: 	}
174: 
175: 	_ = s.ds.Property(ctx).Put(consts.LastScanErrorKey, "")
176: 
177: 	if state.changesDetected.Load() {
178: 		state.sendProgress(&ProgressInfo{ChangesDetected: true})
179: 	}
180: 
181: 	if state.isSelectiveScan() {
182: 		log.Info(ctx, "Scanner: Finished scanning selected folders", "duration", time.Since(startTime), "numTargets", len(targets))
183: 	} else {
184: 		log.Info(ctx, "Scanner: Finished scanning all libraries", "duration", time.Since(startTime))
185: 	}
186: }
