188: // prepareLibrariesForScan initializes the scan for all libraries in the state.
189: // It calls ScanBegin for libraries that haven't started scanning yet (LastScanStartedAt is zero),
190: // reloads them to get the updated state, and filters out any libraries that fail to initialize.
191: func (s *scannerImpl) prepareLibrariesForScan(ctx context.Context, state *scanState) error {
192: 	var successfulLibs []model.Library
193: 
194: 	for _, lib := range state.libraries {
195: 		if lib.LastScanStartedAt.IsZero() {
196: 			// This is a new scan - mark it as started
197: 			err := s.ds.Library(ctx).ScanBegin(lib.ID, state.fullScan)
198: 			if err != nil {
199: 				log.Error(ctx, "Scanner: Error marking scan start", "lib", lib.Name, err)
200: 				state.sendWarning(err.Error())
201: 				continue
202: 			}
203: 
204: 			// Reload library to get updated state (timestamps, etc.)
205: 			reloadedLib, err := s.ds.Library(ctx).Get(lib.ID)
206: 			if err != nil {
207: 				log.Error(ctx, "Scanner: Error reloading library", "lib", lib.Name, err)
208: 				state.sendWarning(err.Error())
209: 				continue
210: 			}
211: 			lib = *reloadedLib
212: 		} else {
213: 			// This is a resumed scan
214: 			log.Debug(ctx, "Scanner: Resuming previous scan", "lib", lib.Name,
215: 				"lastScanStartedAt", lib.LastScanStartedAt, "fullScan", lib.FullScanInProgress)
216: 		}
217: 
218: 		successfulLibs = append(successfulLibs, lib)
219: 	}
220: 
221: 	if len(successfulLibs) == 0 {
222: 		return fmt.Errorf("no libraries available for scanning")
223: 	}
224: 
225: 	// Update state with only successfully initialized libraries
226: 	state.libraries = successfulLibs
227: 	return nil
228: }
