230: func (s *scannerImpl) runGC(ctx context.Context, state *scanState) func() error {
231: 	return func() error {
232: 		state.sendProgress(&ProgressInfo{ForceUpdate: true})
233: 		return s.ds.WithTx(func(tx model.DataStore) error {
234: 			if state.changesDetected.Load() {
235: 				start := time.Now()
236: 
237: 				// For selective scans, extract library IDs to scope GC operations
238: 				var libraryIDs []int
239: 				if state.isSelectiveScan() {
240: 					libraryIDs = slices.Collect(maps.Keys(state.targets))
241: 					log.Debug(ctx, "Scanner: Running selective GC", "libraryIDs", libraryIDs)
242: 				}
243: 
244: 				err := tx.GC(ctx, libraryIDs...)
245: 				if err != nil {
246: 					log.Error(ctx, "Scanner: Error running GC", err)
247: 					return fmt.Errorf("running GC: %w", err)
248: 				}
249: 				log.Debug(ctx, "Scanner: GC completed", "elapsed", time.Since(start))
250: 			} else {
251: 				log.Debug(ctx, "Scanner: No changes detected, skipping GC")
252: 			}
253: 			return nil
254: 		}, "scanner: GC")
255: 	}
256: }
