292: func (s *scannerImpl) runUpdateLibraries(ctx context.Context, state *scanState) func() error {
293: 	return func() error {
294: 		start := time.Now()
295: 		return s.ds.WithTx(func(tx model.DataStore) error {
296: 			for _, lib := range state.libraries {
297: 				err := tx.Library(ctx).ScanEnd(lib.ID)
298: 				if err != nil {
299: 					log.Error(ctx, "Scanner: Error updating last scan completed", "lib", lib.Name, err)
300: 					return fmt.Errorf("updating last scan completed: %w", err)
301: 				}
302: 				err = tx.Property(ctx).Put(consts.PIDTrackKey, conf.Server.PID.Track)
303: 				if err != nil {
304: 					log.Error(ctx, "Scanner: Error updating track PID conf", err)
305: 					return fmt.Errorf("updating track PID conf: %w", err)
306: 				}
307: 				err = tx.Property(ctx).Put(consts.PIDAlbumKey, conf.Server.PID.Album)
308: 				if err != nil {
309: 					log.Error(ctx, "Scanner: Error updating album PID conf", err)
310: 					return fmt.Errorf("updating album PID conf: %w", err)
311: 				}
312: 				if state.changesDetected.Load() {
313: 					log.Debug(ctx, "Scanner: Refreshing library stats", "lib", lib.Name)
314: 					if err := tx.Library(ctx).RefreshStats(lib.ID); err != nil {
315: 						log.Error(ctx, "Scanner: Error refreshing library stats", "lib", lib.Name, err)
316: 						return fmt.Errorf("refreshing library stats: %w", err)
317: 					}
318: 				} else {
319: 					log.Debug(ctx, "Scanner: No changes detected, skipping library stats refresh", "lib", lib.Name)
320: 				}
321: 			}
322: 			log.Debug(ctx, "Scanner: Updated libraries after scan", "elapsed", time.Since(start), "numLibraries", len(state.libraries))
323: 			return nil
324: 		}, "scanner: update libraries")
325: 	}
326: }
