53: // CallScan starts an in-process scan of specific library/folder pairs.
54: // If targets is empty, it scans all libraries.
55: // This is meant to be called from the command line (see cmd/scan.go).
56: func CallScan(ctx context.Context, ds model.DataStore, pls core.Playlists, fullScan bool, targets []model.ScanTarget) (<-chan *ProgressInfo, error) {
57: 	release, err := lockScan(ctx)
58: 	if err != nil {
59: 		return nil, err
60: 	}
61: 	defer release()
62: 
63: 	ctx = auth.WithAdminUser(ctx, ds)
64: 	progress := make(chan *ProgressInfo, 100)
65: 	go func() {
66: 		defer close(progress)
67: 		scanner := &scannerImpl{ds: ds, cw: artwork.NoopCacheWarmer(), pls: pls}
68: 		scanner.scanFolders(ctx, fullScan, targets, progress)
69: 	}()
70: 	return progress, nil
71: }
