261: func lockScan(ctx context.Context) (func(), error) {
262: 	if !running.CompareAndSwap(false, true) {
263: 		log.Debug(ctx, "Scanner already running, ignoring request")
264: 		return func() {}, ErrAlreadyScanning
265: 	}
266: 	return func() {
267: 		running.Store(false)
268: 	}, nil
269: }
