271: func (s *controller) trackProgress(ctx context.Context, progress <-chan *ProgressInfo) ([]string, error) {
272: 	s.count.Store(0)
273: 	s.folderCount.Store(0)
274: 	s.changesDetected = false
275: 
276: 	var warnings []string
277: 	var errs []error
278: 	for p := range pl.ReadOrDone(ctx, progress) {
279: 		if p.Error != "" {
280: 			errs = append(errs, errors.New(p.Error))
281: 			continue
282: 		}
283: 		if p.Warning != "" {
284: 			warnings = append(warnings, p.Warning)
285: 			continue
286: 		}
287: 		if p.ChangesDetected {
288: 			s.changesDetected = true
289: 			continue
290: 		}
291: 		s.count.Add(p.FileCount)
292: 		if p.FileCount > 0 {
293: 			s.folderCount.Add(1)
294: 		}
295: 
296: 		scanType, elapsed, lastErr := s.getScanInfo(ctx)
297: 		status := &events.ScanStatus{
298: 			Scanning:    true,
299: 			Count:       int64(s.count.Load()),
300: 			FolderCount: int64(s.folderCount.Load()),
301: 			Error:       lastErr,
302: 			ScanType:    scanType,
303: 			ElapsedTime: elapsed,
304: 		}
305: 		if s.limiter != nil && !p.ForceUpdate {
306: 			s.limiter.Do(func() { s.sendMessage(ctx, status) })
307: 		} else {
308: 			s.sendMessage(ctx, status)
309: 		}
310: 	}
311: 	return warnings, errors.Join(errs...)
312: }
313: 
314: func (s *controller) sendMessage(ctx context.Context, status *events.ScanStatus) {
315: 	s.broker.SendBroadcastMessage(ctx, status)
316: }
