    23→// integrationCtx returns an admin context suitable for scanner integration tests.
    24→func integrationCtx() context.Context {
    25→	return request.WithUser(context.Background(), model.User{ID: "itestuser", IsAdmin: true})
    26→}
    27→
    28→// setupScannerIntegration initialises a fresh DB schema, a MockDataStore backed by
    29→// the real persistence layer, and a Scanner instance.  It also creates the
    30→// mandatory admin user record and a single library that maps to the supplied
    31→// storage scheme.  All state is cleaned up via t.Cleanup.
    32→func setupScannerIntegration(t *testing.T, scheme string) (context.Context, *tests.MockDataStore, model.Scanner, model.Library) {
    33→	t.Helper()
    34→
    35→	tests.Init(t, true)
    36→
    37→	// Save and restore global config around each test.
    38→	restore := configtest.SetupConfig()
    39→	t.Cleanup(restore)
    40→
    41→	ctx := integrationCtx()
    42→
    43→	// Recreate the schema from scratch so every test starts with an empty DB.
    44→	db.Init(ctx)
    45→	t.Cleanup(func() {
    46→		if err := tests.ClearDB(); err != nil {
    47→			t.Logf("ClearDB: %v", err)
    48→		}
    49→	})
    50→
    51→	ds := &tests.MockDataStore{RealDS: persistence.New(db.Db())}
    52→
    53→	// The scanner requires an admin user to exist in the DB.
    54→	adminUser := model.User{
    55→		ID:          "itestuser",
    56→		UserName:    "admin",
    57→		Name:        "Admin User",
    58→		IsAdmin:     true,
    59→		NewPassword: "password",
    60→	}
    61→	if err := ds.User(ctx).Put(&adminUser); err != nil {
    62→		t.Fatalf("create admin user: %v", err)
    63→	}
    64→
    65→	s := scanner.New(ctx, ds, artwork.NoopCacheWarmer(), events.NoopBroker(),
    66→		core.NewPlaylists(ds), metrics.NewNoopInstance())
    67→
    68→	lib := model.Library{ID: 1, Name: "Integration Test Library", Path: scheme + ":///music"}
    69→	if err := ds.Library(ctx).Put(&lib); err != nil {
    70→		t.Fatalf("create library: %v", err)
    71→	}
    72→
    73→	return ctx, ds, s, lib
    74→}
