    76→// registerFS creates and registers a FakeFS under the given storage scheme.
    77→func registerFS(scheme string, files fstest.MapFS) storagetest.FakeFS {
    78→	fs := storagetest.FakeFS{}
    79→	fs.SetFiles(files)
    80→	storagetest.Register(scheme, &fs)
    81→	return fs
    82→}
