import (
	"context"
	"testing"
	"testing/fstest"

	"github.com/Masterminds/squirrel"
	"github.com/navidrome/navidrome/conf/configtest"
	"github.com/navidrome/navidrome/core"
	"github.com/navidrome/navidrome/core/artwork"
	"github.com/navidrome/navidrome/core/metrics"
	"github.com/navidrome/navidrome/core/storage/storagetest"
	"github.com/navidrome/navidrome/db"
	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/model/request"
	"github.com/navidrome/navidrome/persistence"
	"github.com/navidrome/navidrome/scanner"
	"github.com/navidrome/navidrome/server/events"
	"github.com/navidrome/navidrome/tests"
)

// integrationCtx returns an admin context suitable for scanner integration tests.
func integrationCtx() context.Context {
	return request.WithUser(context.Background(), model.User{ID: "itestuser", IsAdmin: true})
}

// setupScannerIntegration initialises a fresh DB schema, a MockDataStore backed by
// the real persistence layer, and a Scanner instance.  It also creates the
// mandatory admin user record and a single library that maps to the supplied
// storage scheme.  All state is cleaned up via t.Cleanup.
func setupScannerIntegration(t *testing.T, scheme string) (context.Context, *tests.MockDataStore, model.Scanner, model.Library) {
	t.Helper()

	tests.Init(t, true)

	// Save and restore global config around each test.
	restore := configtest.SetupConfig()
	t.Cleanup(restore)

	ctx := integrationCtx()

	// Recreate the schema from scratch so every test starts with an empty DB.
	db.Init(ctx)
	t.Cleanup(func() {
		if err := tests.ClearDB(); err != nil {
			t.Logf("ClearDB: %v", err)
		}
	})

	ds := &tests.MockDataStore{RealDS: persistence.New(db.Db())}

	// The scanner requires an admin user to exist in the DB.
	adminUser := model.User{
		ID:          "itestuser",
		UserName:    "admin",
		Name:        "Admin User",
		IsAdmin:     true,
		NewPassword: "password",
	}
	if err := ds.User(ctx).Put(&adminUser); err != nil {
		t.Fatalf("create admin user: %v", err)
	}

	s := scanner.New(ctx, ds, artwork.NoopCacheWarmer(), events.NoopBroker(),
		core.NewPlaylists(ds), metrics.NewNoopInstance())

	lib := model.Library{ID: 1, Name: "Integration Test Library", Path: scheme + ":///music"}
	if err := ds.Library(ctx).Put(&lib); err != nil {
		t.Fatalf("create library: %v", err)
	}

	return ctx, ds, s, lib
}

// registerFS creates and registers a FakeFS under the given storage scheme.
func registerFS(scheme string, files fstest.MapFS) storagetest.FakeFS {
	fs := storagetest.FakeFS{}
	fs.SetFiles(files)
	storagetest.Register(scheme, &fs)
	return fs
}

// ── helpers ────────────────────────────────────────────────────────────────

func mustScanAll(t *testing.T, s model.Scanner, ctx context.Context, full bool) {
	t.Helper()
	if _, err := s.ScanAll(ctx, full); err != nil {
		t.Fatalf("ScanAll(full=%v): %v", full, err)
	}
}

// ── Tests ──────────────────────────────────────────────────────────────────

// TestScannerFullScan_ImportsMediaFiles verifies that a full scan discovers
// every audio file in the fake filesystem and persists MediaFile records for
// each one, exercising the file-discovery and DB-persistence pipeline stages.
func TestScannerFullScan_ImportsMediaFiles(t *testing.T) {
	const scheme = "it_import"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	revolver := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Revolver",
		"year":        1966,
	})
	registerFS(scheme, fstest.MapFS{
		"The Beatles/Revolver/01 - Taxman.mp3":        revolver(storagetest.Track(1, "Taxman")),
		"The Beatles/Revolver/02 - Eleanor Rigby.mp3": revolver(storagetest.Track(2, "Eleanor Rigby")),
		"The Beatles/Revolver/03 - I'm Only Sleeping.mp3": revolver(storagetest.Track(3, "I'm Only Sleeping")),
	})

	mustScanAll(t, s, ctx, true)

	mfs, err := ds.MediaFile(ctx).GetAll()
	if err != nil {
		t.Fatalf("GetAll mediafiles: %v", err)
	}
	if len(mfs) != 3 {
		t.Errorf("expected 3 media files, got %d", len(mfs))
	}

	titles := make(map[string]bool)
	for _, mf := range mfs {
		titles[mf.Title] = true
	}
	for _, want := range []string{"Taxman", "Eleanor Rigby", "I'm Only Sleeping"} {
		if !titles[want] {
			t.Errorf("missing track %q in imported media files", want)
		}
	}
}

// TestScannerFullScan_CreatesAlbumsAndArtists verifies that the scanner
// correctly creates Album and Artist records during a full scan, covering the
// album-refresh pipeline stage and artist DB persistence.
