// TestScannerFullScan_ImportsMediaFiles verifies that a full scan discovers
// every audio file in the fake filesystem and persists MediaFile records for
// each one, exercising the file-discovery and DB-persistence pipeline stages.
func TestScannerFullScan_ImportsMediaFiles(t *testing.T) {
	const scheme = "it_import"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	revolver := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Revolver",
		"year":        1966,
	})
	registerFS(scheme, fstest.MapFS{
		"The Beatles/Revolver/01 - Taxman.mp3":        revolver(storagetest.Track(1, "Taxman")),
		"The Beatles/Revolver/02 - Eleanor Rigby.mp3": revolver(storagetest.Track(2, "Eleanor Rigby")),
		"The Beatles/Revolver/03 - I'm Only Sleeping.mp3": revolver(storagetest.Track(3, "I'm Only Sleeping")),
	})

	mustScanAll(t, s, ctx, true)

	mfs, err := ds.MediaFile(ctx).GetAll()
	if err != nil {
		t.Fatalf("GetAll mediafiles: %v", err)
	}
	if len(mfs) != 3 {
		t.Errorf("expected 3 media files, got %d", len(mfs))
	}

	titles := make(map[string]bool)
	for _, mf := range mfs {
		titles[mf.Title] = true
	}
	for _, want := range []string{"Taxman", "Eleanor Rigby", "I'm Only Sleeping"} {
		if !titles[want] {
			t.Errorf("missing track %q in imported media files", want)
		}
	}
}

// TestScannerFullScan_CreatesAlbumsAndArtists verifies that the scanner
// correctly creates Album and Artist records during a full scan, covering the
// album-refresh pipeline stage and artist DB persistence.
func TestScannerFullScan_CreatesAlbumsAndArtists(t *testing.T) {
	const scheme = "it_albums"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	help := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Help!",
		"year":        1965,
	})
	revolver := storagetest.Template(map[string]any{
		"albumartist": "The Beatles",
		"album":       "Revolver",
		"year":        1966,
	})
	registerFS(scheme, fstest.MapFS{
		"The Beatles/Help!/01 - Help!.mp3":         help(storagetest.Track(1, "Help!")),
		"The Beatles/Help!/02 - Night Before.mp3":  help(storagetest.Track(2, "The Night Before")),
		"The Beatles/Revolver/01 - Taxman.mp3":     revolver(storagetest.Track(1, "Taxman")),
		"The Beatles/Revolver/02 - Rigby.mp3":      revolver(storagetest.Track(2, "Eleanor Rigby")),
	})

	mustScanAll(t, s, ctx, true)

	// Albums
	albums, err := ds.Album(ctx).GetAll(model.QueryOptions{Sort: "name"})
	if err != nil {
		t.Fatalf("GetAll albums: %v", err)
	}
	if len(albums) != 2 {
		t.Errorf("expected 2 albums, got %d", len(albums))
	}
	albumNames := make(map[string]int) // name → song count
	for _, a := range albums {
		albumNames[a.Name] = a.SongCount
	}
	if sc := albumNames["Help!"]; sc != 2 {
		t.Errorf("Help! album: expected 2 songs, got %d", sc)
	}
	if sc := albumNames["Revolver"]; sc != 2 {
		t.Errorf("Revolver album: expected 2 songs, got %d", sc)
	}

	// Artists
	artists, err := ds.Artist(ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"name": "The Beatles"},
	})
	if err != nil {
		t.Fatalf("GetAll artists: %v", err)
	}
	if len(artists) != 1 {
		t.Errorf("expected 1 artist named 'The Beatles', got %d", len(artists))
	}
}

// TestScannerMetadata_ExtractsTrackFields verifies that tag metadata (title,
// album, artist, year, track number) stored in the fake filesystem is
// faithfully extracted and persisted in the MediaFile record, covering the
// metadata-extraction pipeline stage.
func TestScannerMetadata_ExtractsTrackFields(t *testing.T) {
	const scheme = "it_meta"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	tmpl := storagetest.Template(map[string]any{
		"artist":      "Pink Floyd",
		"albumartist": "Pink Floyd",
		"album":       "The Dark Side of the Moon",
		"year":        1973,
		"genre":       "Progressive Rock",
	})
	registerFS(scheme, fstest.MapFS{
		"Pink Floyd/The Dark Side of the Moon/01 - Speak to Me.mp3": tmpl(
			storagetest.Track(1, "Speak to Me"),
		),
	})

	mustScanAll(t, s, ctx, true)

	mfs, err := ds.MediaFile(ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"title": "Speak to Me"},
	})
	if err != nil {
		t.Fatalf("GetAll mediafiles: %v", err)
	}
	if len(mfs) == 0 {
		t.Fatal("expected track 'Speak to Me' to be imported, but it was not found")
	}

	mf := mfs[0]
	if mf.Title != "Speak to Me" {
		t.Errorf("title: got %q, want %q", mf.Title, "Speak to Me")
	}
	if mf.Album != "The Dark Side of the Moon" {
		t.Errorf("album: got %q, want %q", mf.Album, "The Dark Side of the Moon")
	}
	if mf.AlbumArtist != "Pink Floyd" {
		t.Errorf("album artist: got %q, want %q", mf.AlbumArtist, "Pink Floyd")
	}
	if mf.Year != 1973 {
		t.Errorf("year: got %d, want 1973", mf.Year)
	}
	if mf.TrackNumber != 1 {
		t.Errorf("track number: got %d, want 1", mf.TrackNumber)
	}
}

// TestScannerIncrementalScan_NoChanges verifies that a second scan of an
// unchanged library does not duplicate records in the database, covering the
// incremental-scan (no-op) behaviour.
func TestScannerIncrementalScan_NoChanges(t *testing.T) {
	const scheme = "it_incremental"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	tmpl := storagetest.Template(map[string]any{
		"albumartist": "Led Zeppelin",
		"album":       "IV",
		"year":        1971,
	})
	registerFS(scheme, fstest.MapFS{
		"Led Zeppelin/IV/01 - Black Dog.mp3":    tmpl(storagetest.Track(1, "Black Dog")),
		"Led Zeppelin/IV/02 - Rock and Roll.mp3": tmpl(storagetest.Track(2, "Rock and Roll")),
	})

	// First full scan.
	mustScanAll(t, s, ctx, true)

	count, err := ds.MediaFile(ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll after first scan: %v", err)
	}
	if count != 2 {
		t.Fatalf("expected 2 files after first scan, got %d", count)
	}

	// Second scan (incremental) with no filesystem changes.
	mustScanAll(t, s, ctx, false)

	countAfter, err := ds.MediaFile(ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll after incremental scan: %v", err)
	}
	if countAfter != 2 {
		t.Errorf("incremental scan duplicated records: expected 2, got %d", countAfter)
	}

	// Album and artist counts must also remain stable.
	albums, err := ds.Album(ctx).GetAll()
	if err != nil {
		t.Fatalf("GetAll albums after incremental scan: %v", err)
	}
	if len(albums) != 1 {
		t.Errorf("expected 1 album after incremental scan, got %d", len(albums))
	}
}

// TestScannerFileDeletion_MarksMissing verifies that when a file is removed
// from the filesystem and the library is rescanned, the corresponding
// MediaFile record is marked as missing rather than deleted, covering the
// file-deletion-detection pipeline stage.
func TestScannerFileDeletion_MarksMissing(t *testing.T) {
	const scheme = "it_delete"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	tmpl := storagetest.Template(map[string]any{
		"albumartist": "Queen",
		"album":       "A Night at the Opera",
		"year":        1975,
	})
	fsys := registerFS(scheme, fstest.MapFS{
		"Queen/A Night at the Opera/01 - Bohemian Rhapsody.mp3": tmpl(storagetest.Track(1, "Bohemian Rhapsody")),
		"Queen/A Night at the Opera/02 - Love of My Life.mp3":   tmpl(storagetest.Track(2, "Love of My Life")),
	})

	// Full scan — import both tracks.
	mustScanAll(t, s, ctx, true)

	count, err := ds.MediaFile(ctx).CountAll()
	if err != nil {
		t.Fatalf("CountAll: %v", err)
	}
	if count != 2 {
		t.Fatalf("expected 2 files after initial scan, got %d", count)
	}

	// Remove one file from the fake filesystem.
	fsys.Remove("Queen/A Night at the Opera/02 - Love of My Life.mp3")

	// Incremental rescan.
	mustScanAll(t, s, ctx, false)

	// The removed file should now be marked missing, not deleted.
	missingFiles, err := ds.MediaFile(ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"missing": true},
	})
	if err != nil {
		t.Fatalf("GetAll missing files: %v", err)
	}
	if len(missingFiles) != 1 {
		t.Errorf("expected 1 missing file, got %d", len(missingFiles))
	}
	if len(missingFiles) > 0 && missingFiles[0].Title != "Love of My Life" {
		t.Errorf("wrong file marked missing: got %q, want %q", missingFiles[0].Title, "Love of My Life")
	}

	// The surviving track should still be present.
	presentFiles, err := ds.MediaFile(ctx).GetAll(model.QueryOptions{
		Filters: squirrel.Eq{"missing": false},
	})
	if err != nil {
		t.Fatalf("GetAll present files: %v", err)
	}
	if len(presentFiles) != 1 {
		t.Errorf("expected 1 present file, got %d", len(presentFiles))
	}
}

// TestScannerCorruptFile_SkipsAndWarns verifies the negative case: a file
// that returns an I/O error during metadata extraction is skipped with a
// warning, while all other valid files in the same directory are still
// imported successfully.  This covers error-handling in the metadata-
// extraction stage.
func TestScannerCorruptFile_SkipsAndWarns(t *testing.T) {
	const scheme = "it_corrupt"
	ctx, ds, s, _ := setupScannerIntegration(t, scheme)

	tmpl := storagetest.Template(map[string]any{
		"albumartist": "David Bowie",
		"album":       "Heroes",
		"year":        1977,
	})
	fsys := registerFS(scheme, fstest.MapFS{
		"David Bowie/Heroes/01 - Beauty and the Beast.mp3": tmpl(storagetest.Track(1, "Beauty and the Beast")),
		"David Bowie/Heroes/02 - Joe the Lion.mp3":         tmpl(storagetest.Track(2, "Joe the Lion")),
		"David Bowie/Heroes/03 - Heroes.mp3":               tmpl(storagetest.Track(3, "Heroes")),
	})

	// Inject a read error into one of the files to simulate corruption.
	fsys.SetError("David Bowie/Heroes/02 - Joe the Lion.mp3",
		&corruptFileError{"simulated corrupt metadata"})

	warnings, err := s.ScanAll(ctx, true)
	if err != nil {
		t.Fatalf("ScanAll returned unexpected hard error: %v", err)
	}
	// At least one warning should be emitted for the unreadable file.
	if len(warnings) == 0 {
		t.Error("expected warnings for the corrupt file, got none")
	}

	// The two healthy files must still be imported.
	mfs, err := ds.MediaFile(ctx).GetAll()
	if err != nil {
		t.Fatalf("GetAll mediafiles: %v", err)
	}
	if len(mfs) < 2 {
		t.Errorf("expected at least 2 imported files (corrupt one skipped), got %d", len(mfs))
	}
	for _, mf := range mfs {
		if mf.Title == "Joe the Lion" {
			t.Error("corrupt file 'Joe the Lion' should not have been imported")
		}
	}
}

