   247→// TestScannerIncrementalScan_NoChanges verifies that a second scan of an
   248→// unchanged library does not duplicate records in the database, covering the
   249→// incremental-scan (no-op) behaviour.
   250→func TestScannerIncrementalScan_NoChanges(t *testing.T) {
   251→	const scheme = "it_incremental"
   252→	ctx, ds, s, _ := setupScannerIntegration(t, scheme)
   253→
   254→	tmpl := storagetest.Template(map[string]any{
   255→		"albumartist": "Led Zeppelin",
   256→		"album":       "IV",
   257→		"year":        1971,
   258→	})
   259→	registerFS(scheme, fstest.MapFS{
   260→		"Led Zeppelin/IV/01 - Black Dog.mp3":    tmpl(storagetest.Track(1, "Black Dog")),
   261→		"Led Zeppelin/IV/02 - Rock and Roll.mp3": tmpl(storagetest.Track(2, "Rock and Roll")),
   262→	})
   263→
   264→	// First full scan.
   265→	mustScanAll(t, s, ctx, true)
   266→
   267→	count, err := ds.MediaFile(ctx).CountAll()
   268→	if err != nil {
   269→		t.Fatalf("CountAll after first scan: %v", err)
   270→	}
   271→	if count != 2 {
   272→		t.Fatalf("expected 2 files after first scan, got %d", count)
   273→	}
   274→
   275→	// Second scan (incremental) with no filesystem changes.
   276→	mustScanAll(t, s, ctx, false)
   277→
   278→	countAfter, err := ds.MediaFile(ctx).CountAll()
   279→	if err != nil {
   280→		t.Fatalf("CountAll after incremental scan: %v", err)
   281→	}
   282→	if countAfter != 2 {
   283→		t.Errorf("incremental scan duplicated records: expected 2, got %d", countAfter)
   284→	}
   285→
   286→	// Album and artist counts must also remain stable.
   287→	albums, err := ds.Album(ctx).GetAll()
   288→	if err != nil {
   289→		t.Fatalf("GetAll albums after incremental scan: %v", err)
   290→	}
   291→	if len(albums) != 1 {
   292→		t.Errorf("expected 1 album after incremental scan, got %d", len(albums))
   293→	}
   294→}
