   296→// TestScannerFileDeletion_MarksMissing verifies that when a file is removed
   297→// from the filesystem and the library is rescanned, the corresponding
   298→// MediaFile record is marked as missing rather than deleted, covering the
   299→// file-deletion-detection pipeline stage.
   300→func TestScannerFileDeletion_MarksMissing(t *testing.T) {
   301→	const scheme = "it_delete"
   302→	ctx, ds, s, _ := setupScannerIntegration(t, scheme)
   303→
   304→	tmpl := storagetest.Template(map[string]any{
   305→		"albumartist": "Queen",
   306→		"album":       "A Night at the Opera",
   307→		"year":        1975,
   308→	})
   309→	fsys := registerFS(scheme, fstest.MapFS{
   310→		"Queen/A Night at the Opera/01 - Bohemian Rhapsody.mp3": tmpl(storagetest.Track(1, "Bohemian Rhapsody")),
   311→		"Queen/A Night at the Opera/02 - Love of My Life.mp3":   tmpl(storagetest.Track(2, "Love of My Life")),
   312→	})
   313→
   314→	// Full scan — import both tracks.
   315→	mustScanAll(t, s, ctx, true)
   316→
   317→	count, err := ds.MediaFile(ctx).CountAll()
   318→	if err != nil {
   319→		t.Fatalf("CountAll: %v", err)
   320→	}
   321→	if count != 2 {
   322→		t.Fatalf("expected 2 files after initial scan, got %d", count)
   323→	}
   324→
   325→	// Remove one file from the fake filesystem.
   326→	fsys.Remove("Queen/A Night at the Opera/02 - Love of My Life.mp3")
   327→
   328→	// Incremental rescan.
   329→	mustScanAll(t, s, ctx, false)
   330→
   331→	// The removed file should now be marked missing, not deleted.
   332→	missingFiles, err := ds.MediaFile(ctx).GetAll(model.QueryOptions{
   333→		Filters: squirrel.Eq{"missing": true},
   334→	})
   335→	if err != nil {
   336→		t.Fatalf("GetAll missing files: %v", err)
   337→	}
   338→	if len(missingFiles) != 1 {
   339→		t.Errorf("expected 1 missing file, got %d", len(missingFiles))
   340→	}
   341→	if len(missingFiles) > 0 && missingFiles[0].Title != "Love of My Life" {
   342→		t.Errorf("wrong file marked missing: got %q, want %q", missingFiles[0].Title, "Love of My Life")
   343→	}
   344→
   345→	// The surviving track should still be present.
   346→	presentFiles, err := ds.MediaFile(ctx).GetAll(model.QueryOptions{
   347→		Filters: squirrel.Eq{"missing": false},
   348→	})
   349→	if err != nil {
   350→		t.Fatalf("GetAll present files: %v", err)
   351→	}
   352→	if len(presentFiles) != 1 {
   353→		t.Errorf("expected 1 present file, got %d", len(presentFiles))
   354→	}
   355→}
