   357→// TestScannerCorruptFile_SkipsAndWarns verifies the negative case: a folder
   358→// whose tag extraction fails (due to an I/O error on one of its files) is
   359→// skipped with a warning, while files in other, healthy folders are still
   360→// imported successfully.  This covers error-handling in the metadata-
   361→// extraction stage.
   362→//
   363→// When any file in a folder fails tag reading the scanner skips the entire
   364→// folder and emits a progress warning, so the corrupt file is placed in its
   365→// own album directory separate from the valid tracks.
   366→func TestScannerCorruptFile_SkipsAndWarns(t *testing.T) {
   367→	const scheme = "it_corrupt"
   368→	ctx, ds, s, _ := setupScannerIntegration(t, scheme)
   369→
   370→	heroes := storagetest.Template(map[string]any{
   371→		"albumartist": "David Bowie",
   372→		"album":       "Heroes",
   373→		"year":        1977,
   374→	})
   375→	outside := storagetest.Template(map[string]any{
   376→		"albumartist": "David Bowie",
   377→		"album":       "Outside",
   378→		"year":        1995,
   379→	})
   380→
   381→	// Two valid tracks live in one folder; the corrupt file lives in a
   382→	// separate folder so only that folder is skipped by the scanner.
   383→	fsys := registerFS(scheme, fstest.MapFS{
   384→		"David Bowie/Heroes/01 - Beauty and the Beast.mp3": heroes(storagetest.Track(1, "Beauty and the Beast")),
   385→		"David Bowie/Heroes/02 - Heroes.mp3":               heroes(storagetest.Track(2, "Heroes")),
   386→		"David Bowie/Outside/01 - Outside.mp3":             outside(storagetest.Track(1, "Outside")),
   387→	})
   388→
   389→	// Inject a read error on the entire Outside album folder.
   390→	fsys.SetError("David Bowie/Outside/01 - Outside.mp3",
   391→		&corruptFileError{"simulated corrupt metadata"})
   392→
   393→	warnings, err := s.ScanAll(ctx, true)
   394→	if err != nil {
   395→		t.Fatalf("ScanAll returned unexpected hard error: %v", err)
   396→	}
   397→	// At least one warning should be emitted for the unreadable folder.
   398→	if len(warnings) == 0 {
   399→		t.Error("expected warnings for the folder with a corrupt file, got none")
   400→	}
   401→
   402→	// The two healthy tracks in the Heroes folder must be imported.
   403→	mfs, err := ds.MediaFile(ctx).GetAll()
   404→	if err != nil {
   405→		t.Fatalf("GetAll mediafiles: %v", err)
   406→	}
   407→	if len(mfs) < 2 {
   408→		t.Errorf("expected at least 2 imported files from healthy folder, got %d", len(mfs))
   409→	}
   410→	// The corrupt track must NOT have been imported.
   411→	for _, mf := range mfs {
   412→		if mf.Title == "Outside" {
   413→			t.Error("corrupt file 'Outside' should not have been imported")
   414→		}
   415→	}
   416→}
   417→
   418→// corruptFileError is a sentinel error type that satisfies the error interface
   419→// and is used by TestScannerCorruptFile_SkipsAndWarns.
   420→type corruptFileError struct{ msg string }
   421→
   422→func (e *corruptFileError) Error() string { return e.msg }
