168: func (md Metadata) mapDates() (date Date, originalDate Date, releaseDate Date) {
169: 	// Start with defaults
170: 	date = md.Date(model.TagRecordingDate)
171: 	originalDate = md.Date(model.TagOriginalDate)
172: 	releaseDate = md.Date(model.TagReleaseDate)
173: 
174: 	// For some historic reason, taggers have been writing the Release Date of an album to the Date tag,
175: 	// and leave the Release Date tag empty.
176: 	legacyMappings := (originalDate != "") &&
177: 		(releaseDate == "") &&
178: 		(date >= originalDate)
179: 	if legacyMappings {
180: 		return originalDate, originalDate, date
181: 	}
182: 	// when there's no Date, first fall back to Original Date, then to Release Date.
183: 	date = cmp.Or(date, originalDate, releaseDate)
184: 	return date, originalDate, releaseDate
185: }
